//
// idtx_godot_scn_glue — bridges idtx_avatar → the slangc-lowered
// bake_scn_kernel entry point and writes the resulting byte buffer
// out (optionally wrapped as an RSCC zstd envelope).
//
// The slang kernel lives in core/share/godot_scn/godot_scn.cpp,
// generated by `slangc -entry bake_scn_kernel -target cpp` from the
// Lean spec at openusd-fabric/lean/Fabric/Serialization/GodotScn.lean.
// That file declares `bake_scn_kernel(ComputeVaryingInput*, void*
// entryPointParams, void* globalParams)` — slang's runtime calling
// convention. This glue assembles a `GlobalParams_0` struct, fills
// the input buffers, dispatches the single (1,1,1) thread group,
// then reads `buf` back out.
//
// Current state: `bake_scn_kernel` in the Lean spec is the keep-alive
// entry (calls every writer once with zero arguments) that exists to
// keep the writer library alive through slangc's dead-code elimination.
// It produces a deterministic but degenerate `.scn` byte stream — not
// a real serialization of the avatar. The next iteration of
// `GodotScn.lean` will:
//   1. Add a binding for an avatar-descriptor input buffer.
//   2. Replace the keep-alive entry with one that walks the
//      descriptor and calls writers in the correct sequence.
// When that lands, this glue stays the same — it just fills the
// avatar descriptor before dispatching.

#include "idtx_core/idtx_core.h"
#include "idtx_core/idtx_chunker.h"  // for sha512_256 + buffer accessors

#include <cstdint>
#include <cstring>
#include <fstream>
#include <vector>

#include <zstd.h>
#include <slang-cpp-types.h>

// Forward declaration of the slangc-emitted entry. The .cpp is compiled
// into libidtx_core alongside us (added by scons/godot_scn_writers.py).
extern "C" void bake_scn_kernel(
    ComputeVaryingInput* varyingInput,
    void*                entryPointParams,
    void*                globalParams);

// The slang `GlobalParams_0` struct layout matches what the kernel
// expects. Mirrored here so we don't have to include the (very large)
// slangc-emitted godot_scn.cpp directly.
namespace {

struct GlobalParams {
    RWStructuredBuffer<uint32_t> buf;
    StructuredBuffer<uint32_t>   str_data;
    StructuredBuffer<uint32_t>   int_data;
    StructuredBuffer<float>      float_data;
};

constexpr size_t kBufferWordsMax = 64 * 1024;   // 256 KB scratch — plenty for the keep-alive kernel
constexpr size_t kScratchWordsMax = 4 * 1024;   // 16 KB for each input buffer

// Construct a slang-runtime StructuredBuffer from raw memory. The slang
// types are tiny structs with {T* data; size_t count} so we can
// initialize them via brace-init.
template <typename T>
RWStructuredBuffer<T> as_rw(T* data, size_t count) {
    RWStructuredBuffer<T> buf;
    buf.data  = data;
    buf.count = count;
    return buf;
}

template <typename T>
StructuredBuffer<T> as_ro(const T* data, size_t count) {
    StructuredBuffer<T> buf;
    buf.data  = const_cast<T*>(data);
    buf.count = count;
    return buf;
}

// Find the highest written word offset in `buf` after the kernel
// returns. The keep-alive kernel writes a deterministic prefix
// followed by all-zero tail — scan backwards for the last non-zero
// dword to size the output. Real kernels will set offset = end via a
// dedicated output binding.
size_t find_used_bytes(const uint32_t* buf, size_t cap_words) {
    size_t last = 0;
    for (size_t i = 0; i < cap_words; ++i) {
        if (buf[i] != 0) last = i + 1;
    }
    return last * 4;
}

// Wrap a raw .scn byte stream in the RSCC zstd envelope. Format:
//   "RSCC" magic | u32 mode=2 | u32 block_size=4096
//   | u32 total_uncompressed_size | u32 num_blocks
//   | num_blocks * u32 block_compressed_size
//   | concatenated zstd blocks
//   | "RSCC" footer (4 bytes)
// Matches resource_format_binary.cpp's compressed-load expectations.
int32_t wrap_rscc(
    const uint8_t*       raw,
    size_t               raw_len,
    int32_t              block_size,
    std::vector<uint8_t>& out)
{
    if (block_size <= 0) block_size = 4096;
    const size_t bs = size_t(block_size);
    const size_t num_blocks = (raw_len + bs - 1) / bs;

    out.clear();
    out.reserve(raw_len + 64 + num_blocks * 8);

    auto write_u32 = [&](uint32_t v) {
        for (int i = 0; i < 4; ++i) out.push_back(uint8_t(v >> (i * 8)));
    };

    out.insert(out.end(), {'R', 'S', 'C', 'C'});
    write_u32(2u);                            // compression mode = zstd
    write_u32(uint32_t(bs));                  // block_size
    write_u32(uint32_t(raw_len));             // total uncompressed size
    write_u32(uint32_t(num_blocks));          // num blocks

    // Reserve space for per-block compressed sizes; we fill these in
    // after compressing each block.
    const size_t sizes_offset = out.size();
    for (size_t i = 0; i < num_blocks; ++i) write_u32(0);

    // Compress each block.
    for (size_t i = 0; i < num_blocks; ++i) {
        const size_t off  = i * bs;
        const size_t this_len = (off + bs <= raw_len) ? bs : (raw_len - off);
        const size_t bound = ZSTD_compressBound(this_len);
        const size_t pre   = out.size();
        out.resize(pre + bound);
        const size_t written = ZSTD_compress(
            out.data() + pre, bound,
            raw + off,        this_len,
            3);
        if (ZSTD_isError(written)) return 3;
        out.resize(pre + written);
        // Patch the i-th compressed-size entry.
        const size_t entry = sizes_offset + i * 4;
        for (int j = 0; j < 4; ++j) {
            out[entry + j] = uint8_t(written >> (j * 8));
        }
    }

    out.insert(out.end(), {'R', 'S', 'C', 'C'});
    return 0;
}

// Run the slang kernel once and return the byte-length written.
int32_t run_kernel(std::vector<uint8_t>& out_bytes) {
    std::vector<uint32_t> buf_words(kBufferWordsMax, 0);
    std::vector<uint32_t> str_words(kScratchWordsMax, 0);
    std::vector<uint32_t> int_words(kScratchWordsMax, 0);
    std::vector<float>    flt_words(kScratchWordsMax, 0.0f);

    GlobalParams gp;
    gp.buf        = as_rw(buf_words.data(), buf_words.size());
    gp.str_data   = as_ro(str_words.data(), str_words.size());
    gp.int_data   = as_ro(int_words.data(), int_words.size());
    gp.float_data = as_ro(flt_words.data(), flt_words.size());

    ComputeVaryingInput vi = {};
    vi.startGroupID = uint3{0, 0, 0};
    vi.endGroupID   = uint3{1, 1, 1};

    bake_scn_kernel(&vi, nullptr, &gp);

    const size_t used = find_used_bytes(buf_words.data(), buf_words.size());
    out_bytes.resize(used);
    if (used > 0) {
        std::memcpy(out_bytes.data(),
                    reinterpret_cast<const uint8_t*>(buf_words.data()),
                    used);
    }
    return 0;
}

} // namespace

// ---------------------------------------------------------------------
// Public glue API — called by core/src/idtx_export_scn.cpp when
// IDTX_GODOT_SCN_AVAILABLE is defined.
// ---------------------------------------------------------------------

extern "C" int32_t idtx_godot_scn_serialize(
    const idtx_avatar_t* /*avatar*/,
    const char*          path,
    const idtx_scn_opts_t* opts)
{
    if (path == nullptr) return 1;

    std::vector<uint8_t> raw;
    int32_t rc = run_kernel(raw);
    if (rc != 0) return rc;

    std::vector<uint8_t> wire;
    if (opts != nullptr && opts->compression == IDTX_SCN_ZSTD) {
        rc = wrap_rscc(raw.data(), raw.size(), opts->block_size, wire);
        if (rc != 0) return rc;
    } else {
        wire = std::move(raw);
    }

    std::ofstream f(path, std::ios::binary);
    if (!f) return 2;
    if (!wire.empty()) {
        f.write(reinterpret_cast<const char*>(wire.data()),
                std::streamsize(wire.size()));
    }
    if (!f) return 2;
    return 0;
}

extern "C" int64_t idtx_godot_scn_serialize_to_buffer(
    const idtx_avatar_t* /*avatar*/,
    uint8_t*             out_buf,
    size_t               out_cap,
    const idtx_scn_opts_t* opts)
{
    std::vector<uint8_t> raw;
    int32_t rc = run_kernel(raw);
    if (rc != 0) return -rc;

    std::vector<uint8_t> wire;
    if (opts != nullptr && opts->compression == IDTX_SCN_ZSTD) {
        rc = wrap_rscc(raw.data(), raw.size(), opts->block_size, wire);
        if (rc != 0) return -rc;
    } else {
        wire = std::move(raw);
    }

    // Size-query path: caller asks for the required capacity.
    if (out_buf == nullptr || out_cap == 0) {
        return int64_t(wire.size());
    }
    if (out_cap < wire.size()) {
        return -int64_t(wire.size());  // negative size = "need this many bytes"
    }
    std::memcpy(out_buf, wire.data(), wire.size());
    return int64_t(wire.size());
}
